import { create } from "zustand";

interface Store {
    barcode: string;
    setBarcode: () => void;
    resetBarcode: () => void;
}

export const usePOSStore = create<Store>()((set) => ({
    barcode: '',
    setBarcode: () => set((state) => ({ barcode: state.barcode })),
    resetBarcode: () => set(() => ({ barcode: '' })),
}))